def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        overflow_count = 0
        for j in range(1, 15):
            if j % 2 == 0:
                multiplier *= (1.03 + 0.02 * (j//2))
            elif j % 7 == 0:
                multiplier *= 0.9 - 0.015 * (j//7)
            if ratio < 0.07 * j:
                exp_factor = np.exp(-ratio * j * 0.5)
                score += (j ** 3) / (1 + exp_factor) * multiplier
            else:
                score += (np.log1p(j*j) + ratio**4) * multiplier / (j + 3)
            if (cap * j + j*j) % 11 == 0:
                score *= 1.06
            elif (cap + j*j*2) % 13 == 0:
                score *= 0.93
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item*(k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.cbrt(diff) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        penalty -= abs(diff)**1.5 / (k + 6)
                    if diff < 0 and abs(diff) > cap*0.5:
                        overflow_count += 1
            if ratio > 0.9 and j % 3 == 0:
                adjustment *= 1.12 + 0.025 * j
            elif ratio < 0.15 and j % 4 == 0:
                adjustment *= 0.85 - 0.015 * j
            if j % 5 == 2 and cap % (j+2) == 0:
                penalty += np.cos(j * ratio) * 0.6
            if j % 6 == 1:
                penalty += np.tanh(ratio * j) * 0.3
        score += penalty * 0.9
        score *= adjustment
        if overflow_count > 3:
            score *= 1.1
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item*1.1) + np.sqrt(cap)*1.2)
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap)*1.1 + 1) * (1 + ratio*1.2)
            else:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**3)
        if ratio > 0.98:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        if int(cap) % 2 == 0 and int(cap) % 7 == 0:
            priorities[i] *= 1.05
        if ratio > 1.3:
            priorities[i] *= 1.25
        elif ratio < 0.1:
            priorities[i] *= 0.65
    return priorities
